var state = flow.get('facilityState') || {
    baseline: null,
    scanCount: 0,
    changeLog: []
};

if (msg.payload === 'reset') {
    state.baseline = null;
    state.scanCount = 0;
    state.changeLog = [];
    flow.set('facilityState', state);
    flow.set('lastScanData', null);
    node.warn('Baseline reset.');
    return null;
}

state.scanCount += 1;

var baseDistances = [250, 180, 300, 220, 95];
var pointNames = ['North wall', 'East wall', 'South wall', 'West wall', 'Centre object'];

function noise() {
    return (Math.random() - 0.5) * 4;
}

var readings = baseDistances.map(function(base, i) {
    var val = base + noise();
    if (state.scanCount >= 5 && i === 3) val = base + 18 + noise();
    if (state.scanCount >= 10 && i === 4) val = base + 31 + noise();
    return Math.round(val * 10) / 10;
});

msg.payload = {
    timestamp: new Date().toLocaleTimeString(),
    scanCount: state.scanCount,
    pointNames: pointNames,
    readings: readings,
    state: state
};

flow.set('facilityState', state);
return msg;

var data = msg.payload;
var state = flow.get('facilityState') || { baseline: null, scanCount: 0, changeLog: [] };
var THRESHOLD = 10;

if (!state.baseline) {
    state.baseline = data.readings.slice();
    flow.set('facilityState', state);
    var result = {
        status: 'baseline_set',
        timestamp: data.timestamp,
        scanCount: data.scanCount,
        pointNames: data.pointNames,
        readings: data.readings,
        baseline: state.baseline,
        changes: [],
        changeLog: [],
        summary: 'Baseline established',
        alertLevel: 'info'
    };
    flow.set('lastScanData', result);
    msg.payload = result;
    return msg;
}

var changes = [];
data.readings.forEach(function(val, i) {
    var delta = Math.abs(val - state.baseline[i]);
    if (delta > THRESHOLD) {
        changes.push({
            index: i,
            point: data.pointNames[i],
            baseline: state.baseline[i],
            current: val,
            delta: Math.round(delta * 10) / 10,
            direction: val > state.baseline[i] ? 'increased' : 'decreased'
        });
    }
});

if (changes.length > 0) {
    changes.forEach(function(c) {
        state.changeLog.unshift({
            time: data.timestamp,
            scan: data.scanCount,
            point: c.point,
            delta: c.delta,
            direction: c.direction
        });
    });
    if (state.changeLog.length > 30) state.changeLog = state.changeLog.slice(0, 30);
    flow.set('facilityState', state);
}

var alertLevel = changes.length > 0 ? 'alert' : 'clear';
var summary = changes.length > 0 ? changes.length + ' CHANGE(S) DETECTED' : 'All points nominal';

var result = {
    status: alertLevel,
    timestamp: data.timestamp,
    scanCount: data.scanCount,
    pointNames: data.pointNames,
    readings: data.readings,
    baseline: state.baseline,
    changes: changes,
    changeLog: state.changeLog.slice(0, 30),
    summary: summary,
    alertLevel: alertLevel
};

flow.set('lastScanData', result);
msg.payload = result;
return msg;

var d = msg.payload;
var changedIdx = d.changes.map(function(c) { return c.index; });

// ── 1) SCAN STATUS ──────────────────────────────────────────
var statusColor = d.alertLevel === 'alert' ? '#c62828' : d.alertLevel === 'info' ? '#1565c0' : '#2e7d32';
var statusBg    = d.alertLevel === 'alert' ? '#ffebee' : d.alertLevel === 'info' ? '#e3f2fd' : '#e8f5e9';
var statusBorder= d.alertLevel === 'alert' ? '#ef9a9a' : d.alertLevel === 'info' ? '#90caf9' : '#a5d6a7';

var m1 = {
    payload: {
        scanCount: d.scanCount,
        timestamp: d.timestamp,
        summary: d.summary,
        alertLevel: d.alertLevel,
        statusColor: statusColor,
        statusBg: statusBg,
        statusBorder: statusBorder
    }
};

// ── 2) SENSOR MAP ────────────────────────────────────────────
var sensorRows = d.pointNames.map(function(name, i) {
    var isChanged = changedIdx.indexOf(i) >= 0;
    var baseline  = d.baseline ? d.baseline[i] + ' cm' : '---';
    var current   = d.readings[i] + ' cm';
    var delta     = d.baseline ? Math.round(Math.abs(d.readings[i] - d.baseline[i]) * 10) / 10 : 0;
    var isInfo    = d.alertLevel === 'info';

    var rowBg, badgeColor, badgeBg, badgeText;
    if (isInfo) {
        rowBg = '#f0f7ff'; badgeColor = '#1565c0'; badgeBg = '#e3f2fd'; badgeText = 'BASELINE';
    } else if (isChanged) {
        rowBg = '#fff8f7'; badgeColor = '#c62828'; badgeBg = '#ffebee'; badgeText = 'CHANGED';
    } else {
        rowBg = '#fafafa'; badgeColor = '#2e7d32'; badgeBg = '#e8f5e9'; badgeText = 'OK';
    }

    return {
        name: name,
        baseline: baseline,
        current: current,
        delta: isInfo ? '---' : delta + ' cm',
        badgeText: badgeText,
        badgeColor: badgeColor,
        badgeBg: badgeBg,
        rowBg: rowBg
    };
});

var m2 = { payload: { rows: sensorRows } };

// ── 3) CHANGE LOG ────────────────────────────────────────────
var logRows;
if (!d.changeLog || d.changeLog.length === 0) {
    logRows = [];
} else {
    logRows = d.changeLog.map(function(e) {
        return { time: e.time, scan: e.scan, point: e.point, direction: e.direction, delta: '+' + e.delta + ' cm' };
    });
}
var m3 = { payload: { rows: logRows } };

// ── 4) DEBUG ─────────────────────────────────────────────────
var m4 = {
    payload: d.alertLevel === 'alert'
        ? 'CHANGE at scan #' + d.scanCount + ' — ' + d.changes.map(function(c){ return c.point; }).join(', ')
        : 'Scan #' + d.scanCount + ': ' + d.summary
};

return [m1, m2, m3, m4];
